	rp.lsn = lsnp;
	db_rep = dbenv->rep_handle;
	rep = db_rep->region;
	rp.gen = rep->gen; 
	rp.flags = 0;

	/* Do a full scan if user wants to truncate to before the first
	 * checkpoint that we actually wrote */
